import slick.jdbc.{GetResult, PositionedResult, SQLActionBuilder, SQLInterpolation}
import slick.jdbc.SQLInterpolation._
import scala.util.Try

case class Product(id: Long, name: String, description: Option[String], category: Option[String], brand: Option[String], price: BigDecimal, inStock: Boolean)

object Product {
  implicit val getResult: GetResult[Product] = GetResult { r: PositionedResult =>
    Product(
      id = r.nextLong(),
      name = r.nextString(),
      description = r.nextStringOption(),
      category = r.nextStringOption(),
      brand = r.nextStringOption(),
      price = r.nextBigDecimal(),
      inStock = r.nextBoolean()
    )
  }
}

@Singleton
class ProductSearchController @Inject()(
    cc: ControllerComponents,
    dbConfigProvider: DatabaseConfigProvider
)(implicit ec: ExecutionContext) extends AbstractController(cc) {

  private val dbConfig = dbConfigProvider.get[JdbcProfile]
  import dbConfig.profile.api._

  def search: Action[AnyContent] = Action.async { request =>
    val params = request.queryString.view.mapValues(_.headOption.getOrElse("")).toMap

    val conditions = scala.collection.mutable.ArrayBuffer[SQLActionBuilder]()
    val queryParams = scala.collection.mutable.ArrayBuffer[Any]()

    params.get("name").filter(_.nonEmpty).foreach { value =>
      conditions += sql"LOWER(name) LIKE LOWER(${"%" + value + "%"})"
    }

    params.get("category").filter(_.nonEmpty).foreach { value =>
      conditions += sql"category = $value"
    }

    params.get("brand").filter(_.nonEmpty).foreach { value =>
      conditions += sql"brand = $value"
    }

    params.get("minPrice").flatMap(v => Try(BigDecimal(v)).toOption).foreach { value =>
      conditions += sql"price >= $value"
    }

    params.get("maxPrice").flatMap(v => Try(BigDecimal(v)).toOption).foreach { value =>
      conditions += sql"price <= $value"
    }

    params.get("inStock").flatMap(v => Try(v.toBoolean).toOption).foreach { value =>
      conditions += sql"in_stock = $value"
    }

    val whereClause: SQLActionBuilder =
      if (conditions.isEmpty) sql"1 = 1"
      else conditions.reduceLeft((a, b) => a ++ sql" AND " ++ b)

    val limit = params.get("limit").flatMap(v => Try(v.toInt).toOption).getOrElse(50)
    val offset = params.get("offset").flatMap(v => Try(v.toInt).toOption).getOrElse(0)

    val action =
      sql"SELECT * FROM products WHERE " ++ whereClause ++ sql" ORDER BY id DESC LIMIT $limit OFFSET $offset"
        .as[Product]

    dbConfig.db.run(action).map { products =>
      Ok(play.api.libs.json.Json.toJson(products.map { p =>
        play.api.libs.json.Json.obj(
          "id" -> p.id,
          "name" -> p.name,
          "description" -> p.description,
          "category" -> p.category,
          "brand" -> p.brand,
          "price" -> p.price,
          "inStock" -> p.inStock
        )
      }))
    }.recover {
      case e: Throwable => InternalServerError(e.getMessage)
    }
  }
}